      out.write("        <div class=\"modal-content\" style=\"max-width: 600px; max-height: 80vh; display: flex; flex-direction: column;\">\r\n");
      out.write("            <div class=\"modal-header\">\r\n");
      out.write("                <h3>Your Saved Code Snippets</h3>\r\n");
      out.write("                <button class=\"close-btn\" onclick=\"closeHistoryModal()\">\r\n");
      out.write("                    <svg width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\r\n");
      out.write("                        <line x1=\"18\" y1=\"6\" x2=\"6\" y2=\"18\"></line>\r\n");
      out.write("                        <line x1=\"6\" y1=\"6\" x2=\"18\" y2=\"18\"></line>\r\n");
      out.write("                    </svg>\r\n");
      out.write("                </button>\r\n");
      out.write("            </div>\r\n");
      out.write("            <div class=\"modal-body\" style=\"overflow-y: auto; flex: 1; padding: 0.5rem;\">\r\n");
      out.write("                <ul id=\"history-list\" style=\"list-style: none; margin: 0; padding: 0;\">\r\n");
