      out.write("\r\n");
      out.write("    <script>\r\n");
      out.write("    let socket;\r\n");
      out.write("    let outputBox = document.getElementById(\"output\");\r\n");
      out.write("    let outputText = \"\";\r\n");
      out.write("    let currentInput = \"\";\r\n");
      out.write("    let langIcon = document.getElementById(\"lang-icon\");\r\n");
      out.write("\r\n");
      out.write("    const iconsMap = {\r\n");
      out.write("        java: \"devicon-java-plain colored\",\r\n");
      out.write("        python: \"devicon-python-plain colored\",\r\n");
      out.write("        c: \"devicon-c-plain colored\",\r\n");
      out.write("        cpp: \"devicon-cplusplus-plain colored\",\r\n");
      out.write("        html: \"devicon-html5-plain colored\",\r\n");
      out.write("        mysql: \"devicon-mysql-plain colored\"\r\n");
      out.write("    };\r\n");
      out.write("\r\n");
      out.write("    const templates = {\r\n");
      out.write("        java: `import java.util.*; \\n public class Main {\\n    public static void main(String[] args) {\\n        System.out.println(\"Enter numbers:\");\\n        Scanner sc = new Scanner(System.in);\\n        int a = sc.nextInt();\\n        int b = sc.nextInt();\\n        System.out.println(\"Result: \" + (a + b));\\n    }\\n}`,\r\n");
      out.write("        python: `print(\"Enter numbers:\")\\na = int(input())\\nb = int(input())\\nprint(f\"Result: {a + b}\")`,\r\n");
      out.write("        c: `#include <stdio.h>\\n\\nint main() {\\n    int a, b;\\n    printf(\"Enter numbers:\\\\n\");\\n  scanf(\"%d %d\", &a, &b);\\n    printf(\"Result: %d\\\\n\", a + b);\\n    return 0;\\n}`,\r\n");
      out.write("        html: `<!DOCTYPE html>\\n<html>\\n<head>\\n<style>\\n h1 { color: #3b82f6; }\\n</style>\\n</head>\\n<body>\\n\\n<h1>Hello VM Code IDE </h1>\\n<script>\\nconsole.log(\"JS is working!\");\\n<\\/script>\\n\\n</body>\\n</html>`,\r\n");
      out.write("        mysql: `CREATE TABLE intern (\r\n");
      out.write("    id INT PRIMARY KEY,\r\n");
      out.write("    name VARCHAR(50)\r\n");
      out.write("    );\r\n");
      out.write("\r\n");
      out.write("    INSERT INTO intern VALUES (1, 'Madhan');\r\n");
      out.write("    INSERT INTO intern VALUES (2, 'Vignesh');\r\n");
      out.write("\r\n");
      out.write("    SELECT * FROM intern;`\r\n");
      out.write("};\r\n");
      out.write("\r\n");
      out.write("    function appendOutput(text) {\r\n");
      out.write("        outputText += text + \"\\n\";\r\n");
      out.write("        render();\r\n");
      out.write("    }\r\n");
      out.write("    function render() {\r\n");
      out.write("        outputBox.innerText = outputText + currentInput;\r\n");
      out.write("        moveCursorToEnd();\r\n");
      out.write("    }\r\n");
      out.write("    function moveCursorToEnd() {\r\n");
      out.write("        outputBox.focus();\r\n");
      out.write("        let range = document.createRange();\r\n");
      out.write("        range.selectNodeContents(outputBox);\r\n");
      out.write("        range.collapse(false);\r\n");
      out.write("        let sel = window.getSelection();\r\n");
      out.write("        sel.removeAllRanges();\r\n");
      out.write("        sel.addRange(range);\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    function clearOutput() {\r\n");
      out.write("        outputText = \"\";\r\n");
      out.write("        outputBox.innerText = \"\";\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    function setLayout(language) {\r\n");
      out.write("        const preview = document.getElementById(\"preview\");\r\n");
      out.write("        const outputWrapper = document.getElementById(\"output-wrapper\");\r\n");
      out.write("\r\n");
      out.write("        // Update icon\r\n");
      out.write("        langIcon.className = iconsMap[language] || \"devicon-code-plain\";\r\n");
      out.write("\r\n");
      out.write("        if (language === \"html\") {\r\n");
      out.write("            preview.style.display = \"block\";\r\n");
      out.write("            preview.style.height = \"55%\";\r\n");
      out.write("            outputWrapper.style.height = \"45%\";\r\n");
      out.write("        } else {\r\n");
      out.write("            preview.style.display = \"none\";\r\n");
      out.write("            outputWrapper.style.height = \"100%\";\r\n");
      out.write("        }\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    function runCode() {\r\n");
      out.write("        clearOutput();\r\n");
      out.write("\r\n");
      out.write("        let code = editor.getValue();\r\n");
      out.write("        let language = document.getElementById(\"language\").value;\r\n");
      out.write("        setLayout(language);\r\n");
      out.write("\r\n");
      out.write("        if (language === \"html\") {\r\n");
      out.write("            let iframe = document.getElementById(\"preview\");\r\n");
      out.write("             let injectedScript = `\r\n");
